```python
from PyQt4 import QtCore, QtGui

class MyTreeView(QtGui.QTreeView):

    def __init__(self, parent=None):
        super(MyTreeView, self).__init__(parent)
        self.dragThreshold = 10 # 设置拖拽阈值为10像素
        self.dragStartPosition = QtCore.QPoint() # 记录拖拽起始位置

    def mousePressEvent(self, event):
        if event.buttons() == QtCore.Qt.LeftButton:
            index = self.indexAt(event.pos())
            if index.isValid():
                self.dragStartPosition = event.pos()
                super(MyTreeView, self).mousePressEvent(event)

    def dragMoveEvent(self, event):
        distance = (event.pos() - self.dragStartPosition).manhattanLength()
        if distance > self.dragThreshold:
            event.ignore()
        else:
            super(MyTreeView, self).dragMoveEvent(event)

if __name__ == '__main__':
    app = QtGui.QApplication([])
    tree = MyTreeView()

    model = QtGui.QStandardItemModel()
    parentItem = model.invisibleRootItem()

    for i in range(4):
        item = QtGui.QStandardItem('Item {}'.format(i))
        parentItem.appendRow([item])
        for j in range(3):
            child = QtGui.QStandardItem('Child {}'.format(j))
            item.appendRow([child])

    tree.setModel(model)
    tree.show()
    app.exec_()
```

这个示例中创建了一个带有子项的标准模型，并将模型设置为`MyTreeView`的模型。运行这个程序，在TreeView上进行鼠标拖拽操作时，如果距离拖拽起始位置小于10像素，就会进行拖拽操作。如果距离大于10像素，则取消拖拽操作。
